import{_ as e,o,c as t,ae as c}from"./chunks/framework.C7FLYIpo.js";const h=JSON.parse('{"title":"에이전트 부트스트랩","description":"워크스페이스 및 신원 파일을 초기화하는 에이전트 부트스트랩 의식","frontmatter":{"title":"에이전트 부트스트랩","description":"워크스페이스 및 신원 파일을 초기화하는 에이전트 부트스트랩 의식"},"headers":[],"relativePath":"start/bootstrapping.md","filePath":"start/bootstrapping.md","lastUpdated":null}'),d={name:"start/bootstrapping.md"};function r(l,a,s,i,n,p){return o(),t("div",null,[...a[0]||(a[0]=[c('<h1 id="에이전트-부트스트랩" tabindex="-1">에이전트 부트스트랩 <a class="header-anchor" href="#에이전트-부트스트랩" aria-label="Permalink to &quot;에이전트 부트스트랩&quot;">​</a></h1><p>부트스트랩은 에이전트 워크스페이스를 준비하고 신원 정보를 수집하는 <strong>최초 실행</strong> 의식입니다. 온보딩 이후 에이전트가 처음 시작될 때 실행됩니다.</p><h2 id="부트스트랩이-수행하는-작업" tabindex="-1">부트스트랩이 수행하는 작업 <a class="header-anchor" href="#부트스트랩이-수행하는-작업" aria-label="Permalink to &quot;부트스트랩이 수행하는 작업&quot;">​</a></h2><p>첫 에이전트 실행 시 OpenClaw는 워크스페이스(기본값 <code>~/.openclaw/workspace</code>)를 부트스트랩합니다:</p><ul><li><code>AGENTS.md</code>, <code>BOOTSTRAP.md</code>, <code>IDENTITY.md</code>, <code>USER.md</code>를 초기화합니다.</li><li>짧은 Q&amp;A 의식을 실행합니다(한 번에 하나의 질문).</li><li>신원 및 기본 설정을 <code>IDENTITY.md</code>, <code>USER.md</code>, <code>SOUL.md</code>에 기록합니다.</li><li>완료 후 <code>BOOTSTRAP.md</code>를 제거하여 한 번만 실행되도록 합니다.</li></ul><h2 id="실행-위치" tabindex="-1">실행 위치 <a class="header-anchor" href="#실행-위치" aria-label="Permalink to &quot;실행 위치&quot;">​</a></h2><p>부트스트랩은 항상 <strong>게이트웨이 호스트</strong>에서 실행됩니다. macOS 앱이 원격 Gateway에 연결되는 경우, 워크스페이스 및 부트스트랩 파일은 해당 원격 머신에 저장됩니다.</p><div class="info custom-block"><p class="custom-block-title">NOTE</p><p>Gateway가 다른 머신에서 실행 중인 경우, 게이트웨이 호스트(예: <code>user@gateway-host:~/.openclaw/workspace</code>)에서 워크스페이스 파일을 편집하십시오.</p></div><h2 id="관련-문서" tabindex="-1">관련 문서 <a class="header-anchor" href="#관련-문서" aria-label="Permalink to &quot;관련 문서&quot;">​</a></h2><ul><li>macOS 앱 온보딩: <a href="/openclaw-docs-ko/start/onboarding">온보딩</a></li><li>워크스페이스 구조: <a href="/openclaw-docs-ko/concepts/agent-workspace">에이전트 워크스페이스</a></li></ul>',10)])])}const u=e(d,[["render",r]]);export{h as __pageData,u as default};
